import numpy as np

class Layer:
    def __init__(self):
        self.params = {}
        self.grads = {}

    def forward(self, X):
        raise NotImplementedError

    def backward(self, dA):
        raise NotImplementedError

    def update_params(self, learning_rate):
        for key, value in self.grads.items():
            self.params[key] -= learning_rate * value

class Dense(Layer):
    def __init__(self, input_size, output_size, weight_scale=0.01):
        super().__init__()
        self.params['W'] = weight_scale * np.random.randn(input_size, output_size)
        self.params['b'] = np.zeros(output_size)
        self.X = None
        self.dW = None
        self.db = None

    def forward(self, X):
        self.X = X
        return np.dot(X, self.params['W']) + self.params['b']

    def backward(self, dA):
        m = self.X.shape[0]
        self.dW = np.dot(self.X.T, dA) / m
        self.db = np.sum(dA, axis=0) / m
        self.grads['W'] = self.dW
        self.grads['b'] = self.db
        return np.dot(dA, self.params['W'].T)

class ReLU(Layer):
    def __init__(self):
        super().__init__()
        self.X = None

    def forward(self, X):
        self.X = X
        return np.maximum(0, X)

    def backward(self, dA):
        dX = dA.copy()
        dX[self.X <= 0] = 0
        return dX

class Sigmoid(Layer):
    def __init__(self):
        super().__init__()
        self.A = None

    def forward(self, X):
        self.A = 1 / (1 + np.exp(-X))
        return self.A

    def backward(self, dA):
        return dA * self.A * (1 - self.A)

class Softmax(Layer):
    def __init__(self):
        super().__init__()
        self.A = None

    def forward(self, X):
        exp_scores = np.exp(X - np.max(X, axis=1, keepdims=True))
        self.A = exp_scores / np.sum(exp_scores, axis=1, keepdims=True)
        return self.A

    def backward(self, dA):
        return dA

class NeuralNetwork:
    def __init__(self, layers):
        self.layers = layers

    def forward(self, X):
        for layer in self.layers:
            X = layer.forward(X)
        return X

    def backward(self, dA):
        for layer in reversed(self.layers):
            dA = layer.backward(dA)

    def update_params(self, learning_rate):
        for layer in self.layers:
            layer.update_params(learning_rate)

    def train(self, X, y, learning_rate, epochs, loss_function, verbose=True):
        for i in range(epochs):
            # Forward pass
            y_pred = self.forward(X)

            # Compute loss
            loss, dA = loss_function(y_pred, y)

            # Backward pass
            self.backward(dA)

            # Update parameters
            self.update_params(learning_rate)

            if verbose and i % 100 == 0:
                print(f"Epoch {i}, Loss: {loss}")

    def predict(self, X):
        return self.forward(X)

# Loss functions
def mse_loss(y_pred, y_true):
    m = y_true.shape[0]
    loss = np.sum((y_pred - y_true)**2) / m
    dA = 2 * (y_pred - y_true) / m
    return loss, dA

def cross_entropy_loss(y_pred, y_true):
    m = y_true.shape[0]
    # Numerical stability
    y_pred = np.clip(y_pred, 1e-15, 1 - 1e-15)
    loss = -np.sum(y_true * np.log(y_pred)) / m
    dA = (y_pred - y_true) / m # Derivative of softmax cross entropy
    return loss, dA

# Example usage: Regression
if __name__ == '__main__':
    # Regression example
    X_reg = np.linspace(0, 10, 100).reshape(-1, 1)
    y_reg = 2 * X_reg + 1 + np.random.randn(100, 1) * 0.5

    layers_reg = [
        Dense(1, 5),
        ReLU(),
        Dense(5, 1)
    ]

    model_reg = NeuralNetwork(layers_reg)
    model_reg.train(X_reg, y_reg, learning_rate=0.01, epochs=500, loss_function=mse_loss)

    # Classification example
    # Simple XOR dataset
    X_class = np.array([[0, 0], [0, 1], [1, 0], [1, 1]])
    y_class = np.array([[0], [1], [1], [0]])

    layers_class = [
        Dense(2, 4),
        ReLU(),
        Dense(4, 1),
        Sigmoid()
    ]

    model_class = NeuralNetwork(layers_class)

    def binary_cross_entropy_loss(y_pred, y_true):
        m = y_true.shape[0]
        y_pred = np.clip(y_pred, 1e-15, 1 - 1e-15)
        loss = -np.mean(y_true * np.log(y_pred) + (1 - y_true) * np.log(1 - y_pred))
        dA = -(y_true / y_pred - (1 - y_true) / (1 - y_pred)) / m
        return loss, dA

    model_class.train(X_class, y_class, learning_rate=0.1, epochs=5000, loss_function=binary_cross_entropy_loss)

    # Test classification
    predictions = model_class.predict(X_class)
    print("Classification Predictions:")
    print(predictions)

