import numpy as np

class Layer:
    def __init__(self):
        self.params = {}
        self.grads = {}

    def forward(self, X):
        raise NotImplementedError

    def backward(self, dA_prev):
        raise NotImplementedError

    def update_params(self, learning_rate):
        for key, value in self.grads.items():
            self.params[key] -= learning_rate * value

class Dense(Layer):
    def __init__(self, n_inputs, n_neurons, activation=None):
        super().__init__()
        self.params['W'] = np.random.randn(n_inputs, n_neurons) * 0.01
        self.params['b'] = np.zeros((1, n_neurons))
        self.activation = activation
        self.A = None
        self.Z = None

    def forward(self, X):
        self.X = X
        self.Z = np.dot(X, self.params['W']) + self.params['b']
        if self.activation == 'relu':
            self.A = np.maximum(0, self.Z)
        elif self.activation == 'sigmoid':
            self.A = 1 / (1 + np.exp(-self.Z))
        elif self.activation == 'tanh':
            self.A = np.tanh(self.Z)
        else:
            self.A = self.Z  # Linear activation
        return self.A

    def backward(self, dA_prev):
        if self.activation == 'relu':
            dZ = dA_prev * (self.A > 0)
        elif self.activation == 'sigmoid':
            dZ = dA_prev * self.A * (1 - self.A)
        elif self.activation == 'tanh':
            dZ = dA_prev * (1 - np.tanh(self.Z)**2)
        else:
            dZ = dA_prev

        m = self.X.shape[0]
        self.grads['W'] = (1/m) * np.dot(self.X.T, dZ)
        self.grads['b'] = (1/m) * np.sum(dZ, axis=0, keepdims=True)
        dA_prev = np.dot(dZ, self.params['W'].T)
        return dA_prev

class Softmax(Layer):
    def __init__(self):
        super().__init__()
        self.probs = None

    def forward(self, X):
        exp_scores = np.exp(X - np.max(X, axis=1, keepdims=True))
        self.probs = exp_scores / np.sum(exp_scores, axis=1, keepdims=True)
        return self.probs

    def backward(self, Y):
        m = Y.shape[0]
        self.grads['X'] = self.probs - Y
        return self.grads['X']

class Model:
    def __init__(self, layers):
        self.layers = layers

    def forward(self, X):
        A = X
        for layer in self.layers:
            A = layer.forward(A)
        return A

    def backward(self, Y):
        dA = Y
        for layer in reversed(self.layers):
            dA = layer.backward(dA)

    def update_params(self, learning_rate):
        for layer in self.layers:
            layer.update_params(learning_rate)

    def predict(self, X):
        output = self.forward(X)
        return np.argmax(output, axis=1)

def mse_loss(Y_hat, Y):
    return np.mean((Y_hat - Y)**2)

def mse_loss_derivative(Y_hat, Y):
    return 2 * (Y_hat - Y) / Y.size

def cross_entropy_loss(probs, Y):
    m = Y.shape[0]
    correct_log_probs = -np.log(np.sum(probs*Y, axis=1))
    data_loss = np.sum(correct_log_probs)/m
    return data_loss

def one_hot_encode(y, num_classes):
    one_hot = np.zeros((len(y), num_classes))
    one_hot[np.arange(len(y)), y] = 1
    return one_hot

if __name__ == '__main__':
    # Regression Example
    X_reg = np.random.rand(100, 1)
    Y_reg = 2 * X_reg + 1 + 0.1 * np.random.randn(100, 1)

    layers_reg = [
        Dense(1, 10, activation='relu'),
        Dense(10, 1)
    ]
    model_reg = Model(layers_reg)

    learning_rate_reg = 0.01
    epochs_reg = 100

    for i in range(epochs_reg):
        Y_hat = model_reg.forward(X_reg)
        loss = mse_loss(Y_hat, Y_reg)
        dA = mse_loss_derivative(Y_hat, Y_reg)
        model_reg.backward(dA)
        model_reg.update_params(learning_rate_reg)

        if i % 10 == 0:
            print(f"Regression Epoch {i}, Loss: {loss}")

    # Classification Example
    X_class = np.random.rand(100, 2)
    Y_class = np.random.randint(0, 3, 100)  # 3 classes
    num_classes = 3
    Y_class_one_hot = one_hot_encode(Y_class, num_classes)

    layers_class = [
        Dense(2, 10, activation='relu'),
        Dense(10, num_classes)
    ]
    model_class = Model(layers_class)
    model_class.layers.append(Softmax())

    learning_rate_class = 0.1
    epochs_class = 100

    for i in range(epochs_class):
        probs = model_class.forward(X_class)
        loss = cross_entropy_loss(probs, Y_class_one_hot)
        dA = model_class.layers[-1].backward(Y_class_one_hot)
        model_class.backward(dA)
        model_class.update_params(learning_rate_class)

        if i % 10 == 0:
            print(f"Classification Epoch {i}, Loss: {loss}")

    # Make predictions
    predictions = model_class.predict(X_class)
    accuracy = np.mean(predictions == Y_class)
    print(f"Classification Accuracy: {accuracy}")

