    def backward(self, dA_prev):
        raise NotImplementedError

class Dense(Layer):
    def __init__(self, n_in, n_out, weight_scale=0.01):
        super().__init__()
        self.params['W'] = weight_scale * np.random.randn(n_in, n_out)
        self.params['b'] = np.zeros(n_out)
        self.A_prev = None

    def forward(self, A_prev):
        self.A_prev = A_prev
        self.Z = np.dot(A_prev, self.params['W']) + self.params['b']
        return self.Z

    def backward(self, dA):
        m = self.A_prev.shape[0]
        dZ = dA
        dW = (1/m) * np.dot(self.A_prev.T, dZ)
        db = (1/m) * np.sum(dZ, axis=0)
        dA_prev = np.dot(dZ, self.params['W'].T)

        self.grads['W'] = dW
        self.grads['b'] = db
        return dA_prev

class Activation(Layer):
    def __init__(self, activation_type):
        super().__init__()
        self.activation_type = activation_type
        self.Z = None

    def forward(self, Z):
        self.Z = Z
        if self.activation_type == 'relu':
            return np.maximum(0, Z)
        elif self.activation_type == 'sigmoid':
            return 1 / (1 + np.exp(-Z))
        elif self.activation_type == 'tanh':
            return np.tanh(Z)
        else:
            raise ValueError("Invalid activation type")

    def backward(self, dA):
        Z = self.Z
        if self.activation_type == 'relu':
            dZ = np.array(dA, copy=True)
            dZ[Z <= 0] = 0
            return dZ
        elif self.activation_type == 'sigmoid':
            s = 1 / (1 + np.exp(-Z))
            dZ = dA * s * (1 - s)
            return dZ
        elif self.activation_type == 'tanh':
            dZ = dA * (1 - np.tanh(Z)**2)
            return dZ
        else:
            raise ValueError("Invalid activation type")

class Softmax(Layer):
    def __init__(self):
        super().__init__()
        self.probs = None

    def forward(self, Z):
        exp_Z = np.exp(Z - np.max(Z, axis=1, keepdims=True))
        self.probs = exp_Z / np.sum(exp_Z, axis=1, keepdims=True)
        return self.probs

    def backward(self, dA):
        return dA # Softmax is usually combined with cross-entropy loss, so dA is already dZ

class NeuralNetwork:
    def __init__(self, layers):
        self.layers = layers

    def forward(self, X):
        A = X
        for layer in self.layers:
            A = layer.forward(A)
        return A

    def backward(self, dA):
        for layer in reversed(self.layers):
            dA = layer.backward(dA)

    def update_parameters(self, learning_rate):
        for layer in self.layers:
            for key, grad in layer.grads.items():
                layer.params[key] -= learning_rate * grad

    def train(self, X, Y, learning_rate, epochs, loss_function, batch_size=None):
        m = X.shape[0]
        if batch_size is None:
            batch_size = m

        for epoch in range(epochs):
            for i in range(0, m, batch_size):
                X_batch = X[i:i + batch_size]
                Y_batch = Y[i:i + batch_size]

                # Forward pass
                A = self.forward(X_batch)

                # Compute loss
                loss = loss_function(A, Y_batch)

                # Backward pass
                dA = loss_function.backward(A, Y_batch)
                self.backward(dA)

                # Update parameters
                self.update_parameters(learning_rate)

            if epoch % 10 == 0:
                A = self.forward(X)
                loss = loss_function(A, Y)
                print(f"Epoch {epoch}, Loss: {loss}")

    def predict(self, X):
        return self.forward(X)

class MSELoss:
    def __call__(self, Y_hat, Y):
        return np.mean((Y_hat - Y)**2)

    def backward(self, Y_hat, Y):
        return 2 * (Y_hat - Y) / Y.shape[0]

class CrossEntropyLoss:
    def __call__(self, probs, Y):
        m = Y.shape[0]
        log_likelihood = -np.log(probs[range(m), Y])
        loss = np.sum(log_likelihood) / m
        return loss

    def backward(self, probs, Y):
        m = Y.shape[0]
        grad = probs.copy()
        grad[range(m), Y] -= 1
        grad = grad / m
        return grad

