import numpy as np

class Layer:
    def __init__(self, input_size, output_size, activation=None, activation_prime=None):
        self.weights = np.random.randn(input_size, output_size) * 0.01
        self.bias = np.zeros((1, output_size))
        self.activation = activation
        self.activation_prime = activation_prime
        self.input = None
        self.output = None

    def forward(self, input_data):
        self.input = input_data
        self.output = np.dot(input_data, self.weights) + self.bias
        if self.activation:
            self.output = self.activation(self.output)
        return self.output

    def backward(self, output_gradient, learning_rate):
        if self.activation_prime:
            output_gradient = output_gradient * self.activation_prime(self.output)

        weights_gradient = np.dot(self.input.T, output_gradient)
        input_gradient = np.dot(output_gradient, self.weights.T)

        self.weights -= learning_rate * weights_gradient
        self.bias -= learning_rate * np.sum(output_gradient, axis=0, keepdims=True)
        return input_gradient


class NeuralNetwork:
    def __init__(self, input_size, hidden_layers, output_size):
        self.layers = []
        layer_sizes = [input_size] + hidden_layers + [output_size]
        for i in range(len(layer_sizes) - 1):
            activation = None
            activation_prime = None
            if i < len(layer_sizes) - 2:
                activation = self.relu
                activation_prime = self.relu_prime
            self.layers.append(Layer(layer_sizes[i], layer_sizes[i+1], activation, activation_prime))

    def forward(self, input_data):
        output = input_data
        for layer in self.layers:
            output = layer.forward(output)
        return output

    def backward(self, output_gradient, learning_rate):
        gradient = output_gradient
        for layer in reversed(self.layers):
            gradient = layer.backward(gradient, learning_rate)

    def train(self, X_train, y_train, epochs, learning_rate, loss, loss_prime):
        for epoch in range(epochs):
            for x, y in zip(X_train, y_train):
                # forward
                output = self.forward(x)

                # backward
                gradient = loss_prime(y, output)
