class Layer:
    def __init__(self, input_size, output_size, activation=None, activation_prime=None):
        self.weights = np.random.randn(input_size, output_size) * 0.01
        self.bias = np.zeros((1, output_size))
        self.activation = activation
        self.activation_prime = activation_prime
        self.input = None
        self.output = None

    def forward(self, input_data):
        self.input = input_data
        self.output = np.dot(input_data, self.weights) + self.bias
        if self.activation:
            self.output = self.activation(self.output)
        return self.output

    def backward(self, output_gradient, learning_rate):
        if self.activation_prime:
            output_gradient = output_gradient * self.activation_prime(self.output)

        weights_gradient = np.dot(self.input.T, output_gradient)
        input_gradient = np.dot(output_gradient, self.weights.T)

        self.weights -= learning_rate * weights_gradient
        self.bias -= learning_rate * np.sum(output_gradient, axis=0, keepdims=True)
        return input_gradient


