class Sigmoid(Activation):
    def __init__(self):
        super().__init__()

    def forward(self, x):
        self.sigmoid = 1 / (1 + np.exp(-x))
        return self.sigmoid

    def backward(self, da):
        return da * self.sigmoid * (1 - self.sigmoid)

class ReLU(Activation):
    def __init__(self):
        super().__init__()

    def forward(self, x):
        self.x = x
        return np.maximum(0, x)

    def backward(self, da):
        da[self.x <= 0] = 0
        return da

class Linear(Activation):
    def __init__(self):
        super().__init__()

    def forward(self, x):
        return x

    def backward(self, da):
