        self.W = np.random.randn(input_size, output_size) * 0.01
        self.b = np.zeros((1, output_size))
        self.learning_rate = learning_rate

    def forward(self, x):
        self.x = x
        self.z = np.dot(x, self.W) + self.b
        return self.z

    def backward(self, da):
        m = self.x.shape[0]
        self.dW = (1/m) * np.dot(self.x.T, da)
        self.db = (1/m) * np.sum(da, axis=0, keepdims=True)
        self.dx = np.dot(da, self.W.T)

        self.W -= self.learning_rate * self.dW
        self.b -= self.learning_rate * self.db

        return self.dx

class Loss:
    def __init__(self):
        pass

    def forward(self, y_hat, y):
        raise NotImplementedError

    def backward(self, y_hat, y):
        raise NotImplementedError

class MSE(Loss):
    def __init__(self):
        super().__init__()

    def forward(self, y_hat, y):
        self.y_hat = y_hat
        self.y = y
        return np.mean((y_hat - y)**2)

    def backward(self, y_hat, y):
        return 2 * (y_hat - y) / y.shape[0]

class CrossEntropy(Loss):
    def __init__(self):
        super().__init__()

    def forward(self, y_hat, y):
        self.y_hat = y_hat
        self.y = y
        m = y.shape[0]
        log_likelihood = -np.log(y_hat[range(m), y])
        loss = np.sum(log_likelihood) / m
        return loss

    def backward(self, y_hat, y):
        m = y.shape[0]
        grad = y_hat
        grad[range(m), y] -= 1
        grad = grad / m
        return grad

