import numpy as np

class Activation:
    def __init__(self):
        pass

    def forward(self, x):
        raise NotImplementedError

    def backward(self, da):
        raise NotImplementedError

class Sigmoid(Activation):
    def __init__(self):
        super().__init__()

    def forward(self, x):
        self.sigmoid = 1 / (1 + np.exp(-x))
        return self.sigmoid

    def backward(self, da):
        return da * self.sigmoid * (1 - self.sigmoid)

class ReLU(Activation):
    def __init__(self):
        super().__init__()

    def forward(self, x):
        self.x = x
        return np.maximum(0, x)

    def backward(self, da):
        da[self.x <= 0] = 0
        return da

class Linear(Activation):
    def __init__(self):
        super().__init__()

    def forward(self, x):
        return x

    def backward(self, da):
        return da

class Layer:
    def __init__(self):
        pass

    def forward(self, x):
        raise NotImplementedError

    def backward(self, da):
        raise NotImplementedError

class Dense(Layer):
    def __init__(self, input_size, output_size, learning_rate=0.01):
        super().__init__()
        self.W = np.random.randn(input_size, output_size) * 0.01
        self.b = np.zeros((1, output_size))
        self.learning_rate = learning_rate

    def forward(self, x):
        self.x = x
        self.z = np.dot(x, self.W) + self.b
        return self.z

    def backward(self, da):
        m = self.x.shape[0]
        self.dW = (1/m) * np.dot(self.x.T, da)
        self.db = (1/m) * np.sum(da, axis=0, keepdims=True)
        self.dx = np.dot(da, self.W.T)

        self.W -= self.learning_rate * self.dW
        self.b -= self.learning_rate * self.db

        return self.dx

class Loss:
    def __init__(self):
        pass

    def forward(self, y_hat, y):
        raise NotImplementedError

    def backward(self, y_hat, y):
        raise NotImplementedError

class MSE(Loss):
    def __init__(self):
        super().__init__()

    def forward(self, y_hat, y):
        self.y_hat = y_hat
        self.y = y
        return np.mean((y_hat - y)**2)

    def backward(self, y_hat, y):
        return 2 * (y_hat - y) / y.shape[0]

class CrossEntropy(Loss):
    def __init__(self):
        super().__init__()

    def forward(self, y_hat, y):
        self.y_hat = y_hat
        self.y = y
        m = y.shape[0]
        log_likelihood = -np.log(y_hat[range(m), y])
        loss = np.sum(log_likelihood) / m
        return loss

    def backward(self, y_hat, y):
        m = y.shape[0]
        grad = y_hat
        grad[range(m), y] -= 1
        grad = grad / m
        return grad

class Softmax:
    def __init__(self):
        pass

    def forward(self, x):
        exp_scores = np.exp(x - np.max(x, axis=1, keepdims=True))
        self.softmax = exp_scores / np.sum(exp_scores, axis=1, keepdims=True)
        return self.softmax

    def backward(self, da):
        return da

class NeuralNetwork:
    def __init__(self, layers):
        self.layers = layers

    def forward(self, x):
        for layer in self.layers:
            x = layer.forward(x)
        return x

    def backward(self, da):
        for layer in reversed(self.layers):
            da = layer.backward(da)
        return da

    def train(self, x_train, y_train, loss, epochs, batch_size=32):
        num_samples = x_train.shape[0]
        for epoch in range(epochs):
            for i in range(0, num_samples, batch_size):
                x_batch = x_train[i:i+batch_size]
                y_batch = y_train[i:i+batch_size]

                y_hat = self.forward(x_batch)
                l = loss.forward(y_hat, y_batch)
                da = loss.backward(y_hat, y_batch)
                self.backward(da)

            if epoch % 10 == 0:
                y_hat = self.forward(x_train)
                l = loss.forward(y_hat, y_train)
                print(f"Epoch {epoch}, Loss: {l}")

    def predict(self, x):
        return self.forward(x)

