import numpy as np

class Layer:
    def __init__(self):
        self.params = {}
        self.grads = {}

    def forward(self, X):
        raise NotImplementedError

    def backward(self, dA_prev):
        raise NotImplementedError

    def update_params(self, learning_rate):
        for key, grad in self.grads.items():
            self.params[key] -= learning_rate * grad


class Dense(Layer):
    def __init__(self, n_in, n_out, activation='relu', weight_scale=0.01):
        super().__init__()
        self.params['W'] = weight_scale * np.random.randn(n_in, n_out)
        self.params['b'] = np.zeros(n_out)
        self.activation = activation
        self.A_prev = None
        self.Z = None

    def forward(self, A_prev):
        self.A_prev = A_prev
        self.Z = np.dot(A_prev, self.params['W']) + self.params['b']
        if self.activation == 'relu':
            self.A = np.maximum(0, self.Z)
        elif self.activation == 'sigmoid':
            self.A = 1 / (1 + np.exp(-self.Z))
        elif self.activation == 'linear':
            self.A = self.Z
        elif self.activation == 'softmax':
            exp_Z = np.exp(self.Z - np.max(self.Z, axis=1, keepdims=True))
            self.A = exp_Z / np.sum(exp_Z, axis=1, keepdims=True)
        else:
            raise ValueError("Invalid activation function")
        return self.A

    def backward(self, dA):
        if self.activation == 'relu':
            dZ = dA * (self.Z > 0)
        elif self.activation == 'sigmoid':
            sigmoid = 1 / (1 + np.exp(-self.Z))
            dZ = dA * sigmoid * (1 - sigmoid)
        elif self.activation == 'linear':
            dZ = dA
        elif self.activation == 'softmax':
            dZ = dA # Assumes cross-entropy loss was used
        else:
            raise ValueError("Invalid activation function")

        m = self.A_prev.shape[0]
        self.grads['W'] = np.dot(self.A_prev.T, dZ) / m
        self.grads['b'] = np.sum(dZ, axis=0) / m
        dA_prev = np.dot(dZ, self.params['W'].T)
        return dA_prev


class NeuralNetwork:
    def __init__(self, layer_dims, activations, weight_scale=0.01):
        self.layers = []
        for i in range(len(layer_dims) - 1):
            self.layers.append(Dense(layer_dims[i], layer_dims[i+1], activations[i], weight_scale))

    def forward(self, X):
        A = X
        for layer in self.layers:
            A = layer.forward(A)
        return A

    def backward(self, dA):
        for layer in reversed(self.layers):
            dA = layer.backward(dA)

    def update_params(self, learning_rate):
        for layer in self.layers:
            layer.update_params(learning_rate)

    def train(self, X, y, learning_rate, epochs, loss_function='mse', batch_size=None):
        if batch_size is None:
            batch_size = X.shape[0]

        for epoch in range(epochs):
            for i in range(0, X.shape[0], batch_size):
                X_batch = X[i:i+batch_size]
                y_batch = y[i:i+batch_size]

                # Forward pass
                y_pred = self.forward(X_batch)

                # Compute loss
                if loss_function == 'mse':
                    loss = np.mean((y_pred - y_batch)**2)
                    dA = 2 * (y_pred - y_batch) / y_batch.size
                elif loss_function == 'cross_entropy':
                    loss = self.cross_entropy_loss(y_pred, y_batch)
                    dA = y_pred - y_batch # Assumes softmax output
                else:
                    raise ValueError("Invalid loss function")

                # Backward pass
                self.backward(dA)

                # Update parameters
                self.update_params(learning_rate)

            if epoch % (epochs // 10) == 0:
                y_pred_full = self.forward(X)
                if loss_function == 'mse':
                    loss_full = np.mean((y_pred_full - y)**2)
                elif loss_function == 'cross_entropy':
                    loss_full = self.cross_entropy_loss(y_pred_full, y)
                else:
                    raise ValueError("Invalid loss function")
                print(f"Epoch {epoch}, Loss: {loss_full}")

    def predict(self, X):
        return self.forward(X)

    def cross_entropy_loss(self, y_pred, y_true):
        # Assuming y_true is one-hot encoded
        m = y_true.shape[0]
        log_likelihood = -np.log(np.sum(y_pred * y_true, axis=1))
        loss = np.sum(log_likelihood) / m
        return loss


